class Solution {
    public String largestPalindrome(int n, int k) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < n / 2; i++) {
            sb.append('9');
        }
        String firstHalf = sb.toString();
        String palindrome;
        if (n % 2 == 0) {
            palindrome = firstHalf + new StringBuilder(firstHalf).reverse().toString();
        } else {
            palindrome = firstHalf + '9' + new StringBuilder(firstHalf).reverse().toString();
        }
        long num = Long.parseLong(palindrome);
        while (num % k != 0) {
            num--;
            palindrome = String.valueOf(num);
            if (palindrome.length() != n) break;
        }
        return palindrome;
    }
}
efficiency: HIGH
time complexity: O(n)
space complexity: O(n)
